const lead = $json;

const evoBaseUrl = 'https://evo.embarcompany.cloud';
const evoInstance = 'cvi';
const managerGroupJid = '120363426954252951@g.us';

const normalizePetText = (value) => {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/cao\(caes\)/gi, 'cachorro(s)')
    .replace(/cao/gi, 'cachorro')
    .replace(/caes/gi, 'cachorros')
    .replace(/1 cachorro\(s\)/gi, '1 cachorro')
    .replace(/(\d+)\s+cachorro\(s\)/gi, '$1 cachorros')
    .replace(/1 gato\(s\)/gi, '1 gato')
    .replace(/(\d+)\s+gato\(s\)/gi, '$1 gatos')
    .trim();
};

const formatList = (value) => {
  if (Array.isArray(value)) return value.filter(Boolean).join(', ');
  return String(value || '').trim();
};

const clientPhone = lead.whatsapp_e164 || lead.raw_payload?.whatsapp_e164 || '';
const clientDigits = String(clientPhone || lead.whatsapp || '').replace(/\D/g, '');
const displayPhone = lead.whatsapp_international || lead.raw_payload?.whatsapp_international || clientPhone || lead.whatsapp || 'Nao informado';
const email = lead.email_opcional || lead.raw_payload?.email_opcional || lead.raw_payload?.tutor_email || lead.raw_payload?.email || lead.raw_payload?.emailOpcional || 'Nao informado';

const destination = lead.destino_final || 'Destino nao informado';
const origin = lead.cidade_origem || 'Origem nao informada';
const travelWindow = lead.data_viagem || 'Previsao nao informada';
const petSummary = normalizePetText(lead.pet_summary) || 'Pet nao informado';
const petBreed = lead.raca_pet || lead.raw_payload?.raca_pet || 'Nao informado';
const veterinaryProcedures = formatList(lead.procedimentos_veterinarios) || lead.procedimentos_veterinarios_texto || lead.raw_payload?.procedimentos_veterinarios_texto || 'Nao informado';
const createdAt = lead.created_at ? new Date(lead.created_at).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' }) : 'Agora';
const tracking = lead.tracking_params || lead.raw_payload?.tracking_params || {};
const trafficSource = lead.utm_source || lead.src || tracking.utm_source || tracking.src || lead.source || lead.origem || (lead.gclid || lead.gbraid || lead.wbraid || lead.dclid || tracking.gclid || tracking.gbraid || tracking.wbraid || tracking.dclid ? 'google' : lead.fbclid || lead.igshid || lead.ctwa_clid || lead.wamid || lead.tintim_fbid || tracking.fbclid || tracking.igshid || tracking.ctwa_clid || tracking.wamid || tracking.tintim_fbid ? 'meta' : lead.ttclid || lead.tt_lead_id || lead.tt_session_id || tracking.ttclid || tracking.tt_lead_id || tracking.tt_session_id ? 'tiktok' : lead.twclid || tracking.twclid ? 'x/twitter' : lead.rdt_cid || tracking.rdt_cid ? 'reddit' : lead.msclkid || tracking.msclkid ? 'microsoft' : lead.irclickid || tracking.irclickid ? 'impact' : lead.epik || tracking.epik ? 'pinterest' : 'Sem origem');

const text = `Novo lead CVI Facil\n\nTutor: ${lead.nome_tutor || 'Nao informado'}\nWhatsApp: ${lead.whatsapp || 'Nao informado'}\nWhatsApp normalizado: ${displayPhone}\nWhatsApp E164: ${clientPhone || 'Nao informado'}\nEmail: ${email}\n\nOrigem: ${origin}\nDestino: ${destination}\nPrevisao: ${travelWindow}\nPet: ${petSummary}\nRaca: ${petBreed}\nProcedimentos veterinarios: ${veterinaryProcedures}\n\nFonte: ${trafficSource}\nCriado em: ${createdAt}\nLead ID: ${lead.id}\n\nAcionar o tutor pelo WhatsApp acima.`;

return [{
  json: {
    ...lead,
    client_whatsapp_normalized: clientDigits,
    manager_group_jid: managerGroupJid,
    evo_base_url: evoBaseUrl.replace(/\/$/, ''),
    evo_instance: evoInstance,
    evo_message: text
  }
}];

const lead = $('Preparar alerta gestor').item.json;
const response = $json?.data || $json;
const messageId = response?.key?.id || response?.messageId || response?.id || response?.response?.key?.id || null;

return [{
  json: {
    lead_id: lead.id,
    evo_message_id: messageId,
    evo_instance: lead.evo_instance
  }
}];
